// Basic Vertex Shader in GLSL
#version 330 core

// Input attributes from vertex buffer
layout(location = 0) in vec3 aPosition;
layout(location = 1) in vec3 aNormal;
layout(location = 2) in vec2 aTexCoord;

// Output to fragment shader (varyings)
out vec3 vNormal;
out vec3 vFragPos;
out vec2 vTexCoord;

// Uniforms set by application
uniform mat4 uModel;
uniform mat4 uView;
uniform mat4 uProjection;

void main() {
 // Transform position to world space then to clip space
 vec4 worldPos = uModel * vec4(aPosition, 1.0);
 vFragPos = worldPos.xyz;

 // Transform normal to world space (correct for uniform scaling)
 vNormal = mat3(transpose(inverse(uModel))) * aNormal;

 // Pass texture coordinates
 vTexCoord = aTexCoord;

 // Final clip space position
 gl_Position = uProjection * uView * worldPos;
}

// Basic Fragment Shader in GLSL
#version 330 core

// Input from vertex shader (interpolated)
in vec3 vNormal;
in vec3 vFragPos;
in vec2 vTexCoord;

// Output color
out vec4 FragColor;

// Uniforms
uniform vec3 uLightPos;
uniform vec3 uViewPos;
uniform vec3 uLightColor;
uniform vec3 uObjectColor;
sampler2D uTexture;

void main() {
 // Ambient lighting
 float ambientStrength = 0.1;
 vec3 ambient = ambientStrength * uLightColor;

 // Diffuse lighting
 vec3 norm = normalize(vNormal);
 vec3 lightDir = normalize(uLightPos - vFragPos);
 float diff = max(dot(norm, lightDir), 0.0);
 vec3 diffuse = diff * uLightColor;

 // Specular lighting
 float specularStrength = 0.5;
 vec3 viewDir = normalize(uViewPos - vFragPos);
 vec3 reflectDir = reflect(-lightDir, norm);
 float spec = pow(max(dot(viewDir, reflectDir), 0.0), 32);
 vec3 specular = specularStrength * spec * uLightColor;

 // Sample texture
 vec4 texColor = texture(uTexture, vTexCoord);

 // Combine all lighting
 vec3 result = (ambient + diffuse + specular) * uObjectColor;
 FragColor = vec4(result * texColor.rgb, texColor.a);
}

// Geometry Shader for wireframe effect
#version 330 core

layout(triangles) in;
layout(line_strip, max_vertices = 4) out;

in VS_OUT {
 vec3 normal;
 vec3 fragPos;
} gs_in[];

out vec3 vNormal;
out vec3 vFragPos;

uniform float uOutlineWidth;

void main() {
 vec3 a = gl_in[0].gl_Position.xyz;
 vec3 b = gl_in[1].gl_Position.xyz;
 vec3 c = gl_in[2].gl_Position.xyz;

 // Calculate face normal
 vec3 ab = b - a;
 vec3 ac = c - a;
 vec3 faceNormal = normalize(cross(ab, ac));

 // Create expanded vertices for each edge
 vec3 a_out = a - faceNormal * uOutlineWidth;
 vec3 b_out = b - faceNormal * uOutlineWidth;
 vec3 c_out = c - faceNormal * uOutlineWidth;

 // Output expanded triangle (will create outline effect)
 gl_Position = vec4(a_out, 1.0);
 EmitVertex();
 gl_Position = vec4(b_out, 1.0);
 EmitVertex();
 gl_Position = vec4(c_out, 1.0);
 EmitVertex();
 gl_Position = vec4(a_out, 1.0); // Close the loop
 EmitVertex();

 EndPrimitive();
}

// Pseudocode: Render to Multiple Targets

// Setup Framebuffer with multiple color attachments
FUNCTION SetupMRTFramebuffer()
 CREATE FramebufferObject (FBO)

 // Color attachments
 CREATE Texture2D(colorTex0, width, height, RGBA8)
 CREATE Texture2D(colorTex1, width, height, RGBA16F) // HDR

 // Depth attachment
 CREATE Texture2D(depthTex, width, height, DEPTH24_STENCIL8)

 // Attach to FBO
 FramebufferAttachColor(FBO, colorTex0, ATTACHMENT0)
 FramebufferAttachColor(FBO, colorTex1, ATTACHMENT1)
 FramebufferAttachDepth(FBO, depthTex)

 // Set draw buffers for MRT
 SetDrawBuffers([ATTACHMENT0, ATTACHMENT1])

 RETURN FBO
END FUNCTION

// Fragment shader outputs to multiple targets
// GLSL example:
// layout(location = 0) out vec4 outColor0;
// layout(location = 1) out vec4 outColor1;

FUNCTION RenderSceneWithMRT()
 // Bind FBO
 BindFramebuffer(FBO)

 // Set viewport
 SetViewport(0, 0, width, height)

 // Clear all targets
 ClearColorBuffer(ATTACHMENT0, black)
 ClearColorBuffer(ATTACHMENT1, black)
 ClearDepthBuffer(1.0)

 // Bind shader program
 UseProgram(mrtShader)

 // Bind vertex buffers
 BindVertexBuffer(vbo)
 BindIndexBuffer(ebo)

 // Draw
 DrawElements(TRIANGLES, indexCount)

 // Unbind FBO (return to default framebuffer)
 BindFramebuffer(DEFAULT)

 // Use textures for post-processing
 ProcessGBuffer(colorTex0, colorTex1)
END FUNCTION
